/**
 * Returns last N sensor readings for chart display
 * @summary Get sensor data history
 */
export const getGetSensorHistoryUrl = (params?: GetSensorHistoryParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/sensor-data/history?${stringifiedParams}`
    : `/api/sensor-data/history`;
};

